+                content_hash: row.get(5)?,
+                captured_at: row.get(6)?,
+            };
+            let snippet: Option<String> = row.get(7)?;
+            let highlight: Option<String> = row.get(8)?;
+            Ok((id, segment, snippet, highlight))
